import{_ as s,c as t,o as n,a1 as e}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Быстрый старт: Освоение за 5 минут | Plannotator","description":"Изучите установку и настройку Plannotator. Установите CLI за 5 минут, настройте плагин для Claude Code или OpenCode, освойте процессы рецензирования планов и кода.","frontmatter":{"title":"Быстрый старт: Освоение за 5 минут | Plannotator","sidebarTitle":"Освоение за 5 минут","subtitle":"Быстрый старт: Освоение Plannotator за 5 минут","description":"Изучите установку и настройку Plannotator. Установите CLI за 5 минут, настройте плагин для Claude Code или OpenCode, освойте процессы рецензирования планов и кода.","tags":["Быстрый старт","Начало работы","Установка","Claude Code","OpenCode"],"order":1},"headers":[],"relativePath":"ru/backnotprop/plannotator/start/getting-started/index.md","filePath":"ru/backnotprop/plannotator/start/getting-started/index.md"}'),o={name:"ru/backnotprop/plannotator/start/getting-started/index.md"};function l(i,a,r,p,d,c){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="быстрыи-старт-освоение-plannotator-за-5-минут" tabindex="-1">Быстрый старт: Освоение Plannotator за 5 минут <a class="header-anchor" href="#быстрыи-старт-освоение-plannotator-за-5-минут" aria-label="Permalink to &quot;Быстрый старт: Освоение Plannotator за 5 минут&quot;">​</a></h1><h2 id="что-вы-сможете-делать-после-изучения" tabindex="-1">Что вы сможете делать после изучения <a class="header-anchor" href="#что-вы-сможете-делать-после-изучения" aria-label="Permalink to &quot;Что вы сможете делать после изучения&quot;">​</a></h2><ul><li>✅ Понимать основные функции и сценарии использования Plannotator</li><li>✅ Установить Plannotator за 5 минут</li><li>✅ Настроить интеграцию с Claude Code или OpenCode</li><li>✅ Выполнить первое рецензирование плана и кода</li></ul><h2 id="ваша-текущая-ситуация" tabindex="-1">Ваша текущая ситуация <a class="header-anchor" href="#ваша-текущая-ситуация" aria-label="Permalink to &quot;Ваша текущая ситуация&quot;">​</a></h2><p><strong>Plannotator</strong> — это интерактивный инструмент рецензирования для Claude Code и OpenCode, который поможет решить следующие проблемы:</p><p><strong>Проблема 1</strong>: Планы реализации, сгенерированные ИИ, читаются в терминале — много текста, нечёткая структура, рецензирование утомительно.</p><p><strong>Проблема 2</strong>: При необходимости дать ИИ обратную связь приходится описывать текстом &quot;удалить 3-й абзац&quot;, &quot;изменить эту функцию&quot; — высокие затраты на коммуникацию.</p><p><strong>Проблема 3</strong>: При рецензировании кода нужно открывать несколько терминалов или IDE, постоянно переключаться — сложно сосредоточиться.</p><p><strong>Проблема 4</strong>: Члены команды хотят участвовать в рецензировании, но не знают, как делиться содержимым планов.</p><p><strong>Plannotator поможет вам</strong>:</p><ul><li>Визуальный UI вместо чтения в терминале — чёткая структура</li><li>Выделите текст, чтобы добавить комментарий (удаление, замена, комментарий) — точная обратная связь</li><li>Визуальное рецензирование Git diff с поддержкой комментариев на уровне строк</li><li>Функция обмена URL — командная работа без бэкенда</li></ul><h2 id="когда-использовать-этот-инструмент" tabindex="-1">Когда использовать этот инструмент <a class="header-anchor" href="#когда-использовать-этот-инструмент" aria-label="Permalink to &quot;Когда использовать этот инструмент&quot;">​</a></h2><p><strong>Сценарии использования</strong>:</p><ul><li>Использование Claude Code или OpenCode для разработки с помощью ИИ</li><li>Необходимость рецензирования планов реализации, сгенерированных ИИ</li><li>Необходимость проверки изменений кода</li><li>Необходимость делиться планами или результатами рецензирования кода с командой</li></ul><p><strong>Неподходящие сценарии</strong>:</p><ul><li>Полностью ручное написание кода (без планов, сгенерированных ИИ)</li><li>Уже есть полноценный процесс рецензирования кода (например, GitHub PR)</li><li>Нет необходимости в инструменте визуального рецензирования</li></ul><h2 id="основная-концепция" tabindex="-1">Основная концепция <a class="header-anchor" href="#основная-концепция" aria-label="Permalink to &quot;Основная концепция&quot;">​</a></h2><h3 id="что-такое-plannotator" tabindex="-1">Что такое Plannotator <a class="header-anchor" href="#что-такое-plannotator" aria-label="Permalink to &quot;Что такое Plannotator&quot;">​</a></h3><p><strong>Plannotator</strong> — это интерактивный инструмент рецензирования, разработанный для AI Coding Agent (Claude Code, OpenCode), предоставляющий две основные функции:</p><ol><li><strong>Рецензирование планов</strong>: Визуальное рецензирование планов реализации, сгенерированных ИИ, с поддержкой добавления комментариев, одобрения или отклонения</li><li><strong>Рецензирование кода</strong>: Визуальное рецензирование Git diff с поддержкой комментариев на уровне строк и нескольких режимов просмотра</li></ol><h3 id="принцип-работы" tabindex="-1">Принцип работы <a class="header-anchor" href="#принцип-работы" aria-label="Permalink to &quot;Принцип работы&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│   AI Agent      │</span></span>
<span class="line"><span>│ (генерация плана)│</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│   Plannotator   │ ← Локальный HTTP-сервер</span></span>
<span class="line"><span>│  (визуальный UI)│</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│    Браузер      │</span></span>
<span class="line"><span>│ (рецензирование)│</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><p><strong>Основной процесс</strong>:</p><ol><li>AI Agent завершает план или изменения кода</li><li>Plannotator запускает локальный HTTP-сервер и открывает браузер</li><li>Пользователь просматривает план/код в браузере, добавляет комментарии</li><li>Пользователь одобряет или отклоняет, Plannotator возвращает решение AI Agent</li><li>AI Agent продолжает реализацию или вносит изменения на основе обратной связи</li></ol><h3 id="безопасность" tabindex="-1">Безопасность <a class="header-anchor" href="#безопасность" aria-label="Permalink to &quot;Безопасность&quot;">​</a></h3><p><strong>Все данные обрабатываются локально</strong>, не загружаются в облако:</p><ul><li>Содержимое планов, diff кода, комментарии хранятся на вашем локальном компьютере</li><li>Локальный HTTP-сервер использует случайный порт (или фиксированный порт)</li><li>Функция обмена URL реализована путём сжатия данных в хэш URL, без необходимости бэкенда</li></ul><h2 id="🎒-подготовка-к-началу" tabindex="-1">🎒 Подготовка к началу <a class="header-anchor" href="#🎒-подготовка-к-началу" aria-label="Permalink to &quot;🎒 Подготовка к началу&quot;">​</a></h2><p><strong>Системные требования</strong>:</p><ul><li>Операционная система: macOS / Linux / Windows / WSL</li><li>Среда выполнения: Bun (скрипт установки обработает автоматически)</li><li>Среда ИИ: Claude Code 2.1.7+ или OpenCode</li></ul><p><strong>Выбор способа установки</strong>:</p><ul><li>При использовании Claude Code: необходимо установить CLI + плагин</li><li>При использовании OpenCode: необходимо настроить плагин</li><li>Если нужно только рецензирование кода: достаточно установить CLI</li></ul><h2 id="следуите-инструкциям" tabindex="-1">Следуйте инструкциям <a class="header-anchor" href="#следуите-инструкциям" aria-label="Permalink to &quot;Следуйте инструкциям&quot;">​</a></h2><h3 id="шаг-1-установка-plannotator-cli" tabindex="-1">Шаг 1: Установка Plannotator CLI <a class="header-anchor" href="#шаг-1-установка-plannotator-cli" aria-label="Permalink to &quot;Шаг 1: Установка Plannotator CLI&quot;">​</a></h3><p><strong>macOS / Linux / WSL</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://plannotator.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p><strong>Windows PowerShell</strong>:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plannotator.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div><p><strong>Windows CMD</strong>:</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsSL https://plannotator.ai/install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">o install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> del install.cmd</span></span></code></pre></div><p><strong>Вы должны увидеть</strong>: Скрипт установки автоматически загрузит Plannotator CLI, добавит его в системный PATH и отобразит номер версии (например, &quot;plannotator v0.6.7 installed to ...&quot;).</p><div class="tip custom-block"><p class="custom-block-title">Что делает скрипт установки?</p><p>Скрипт установки выполняет:</p><ol><li>Загрузку последней версии Plannotator CLI</li><li>Добавление в системный PATH</li><li>Очистку возможных старых версий</li><li>Автоматическую установку команды <code>/plannotator-review</code> (для рецензирования кода)</li></ol></div><h3 id="шаг-2-настроика-claude-code-опционально" tabindex="-1">Шаг 2: Настройка Claude Code (опционально) <a class="header-anchor" href="#шаг-2-настроика-claude-code-опционально" aria-label="Permalink to &quot;Шаг 2: Настройка Claude Code (опционально)&quot;">​</a></h3><p>Если вы используете Claude Code, необходимо установить плагин.</p><p><strong>Выполните в Claude Code</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin marketplace add backnotprop/plannotator</span></span>
<span class="line"><span>/plugin install plannotator@plannotator</span></span></code></pre></div><p><strong>Важно</strong>: После установки плагина <strong>необходимо перезапустить Claude Code</strong>, чтобы hook заработал.</p><p><strong>Вы должны увидеть</strong>: После успешной установки плагина в списке плагинов Claude Code появится <code>plannotator</code>.</p><div class="info custom-block"><p class="custom-block-title">Ручная настройка (опционально)</p><p>Если вы не хотите использовать систему плагинов, можно настроить hook вручную. Подробности см. в разделе <a href="./../installation-claude-code/">Установка плагина Claude Code</a>.</p></div><h3 id="шаг-3-настроика-opencode-опционально" tabindex="-1">Шаг 3: Настройка OpenCode (опционально) <a class="header-anchor" href="#шаг-3-настроика-opencode-опционально" aria-label="Permalink to &quot;Шаг 3: Настройка OpenCode (опционально)&quot;">​</a></h3><p>Если вы используете OpenCode, необходимо отредактировать файл <code>opencode.json</code>.</p><p><strong>Отредактируйте <code>opencode.json</code></strong>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://opencode.ai/config.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@plannotator/opencode@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Перезапустите OpenCode</strong>.</p><p><strong>Вы должны увидеть</strong>: После перезапуска OpenCode автоматически загрузит плагин, инструмент <code>submit_plan</code> станет доступен.</p><h3 id="шаг-4-первое-рецензирование-плана-пример-с-claude-code" tabindex="-1">Шаг 4: Первое рецензирование плана (пример с Claude Code) <a class="header-anchor" href="#шаг-4-первое-рецензирование-плана-пример-с-claude-code" aria-label="Permalink to &quot;Шаг 4: Первое рецензирование плана (пример с Claude Code)&quot;">​</a></h3><p><strong>Условие запуска</strong>: Попросите Claude Code сгенерировать план реализации и вызвать <code>ExitPlanMode</code>.</p><p><strong>Пример диалога</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Пользователь: Помоги написать план реализации модуля аутентификации пользователей</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude: Хорошо, вот план реализации:</span></span>
<span class="line"><span>1. Создать модель пользователя</span></span>
<span class="line"><span>2. Реализовать API регистрации</span></span>
<span class="line"><span>3. Реализовать API входа</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(вызов ExitPlanMode)</span></span></code></pre></div><p><strong>Вы должны увидеть</strong>:</p><ol><li>Браузер автоматически откроет Plannotator UI</li><li>Отобразится содержимое плана, сгенерированного ИИ</li><li>Можно выделить текст плана, добавить комментарий (удаление, замена, комментарий)</li><li>Внизу кнопки &quot;Approve&quot; и &quot;Request Changes&quot;</li></ol><p><strong>Действия</strong>:</p><ol><li>Просмотрите план в браузере</li><li>Если план в порядке, нажмите <strong>Approve</strong> → ИИ продолжит реализацию</li><li>Если нужны изменения, выделите текст для изменения, нажмите <strong>Delete</strong>, <strong>Replace</strong> или <strong>Comment</strong> → нажмите <strong>Request Changes</strong></li></ol><p><strong>Вы должны увидеть</strong>: После нажатия браузер автоматически закроется, Claude Code получит ваше решение и продолжит выполнение.</p><h3 id="шаг-5-первое-рецензирование-кода" tabindex="-1">Шаг 5: Первое рецензирование кода <a class="header-anchor" href="#шаг-5-первое-рецензирование-кода" aria-label="Permalink to &quot;Шаг 5: Первое рецензирование кода&quot;">​</a></h3><p><strong>Выполните в директории проекта</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>Вы должны увидеть</strong>:</p><ol><li>Браузер откроет страницу рецензирования кода</li><li>Отобразится Git diff (по умолчанию незафиксированные изменения)</li><li>Слева дерево файлов, справа diff viewer</li><li>Нажмите на номер строки, чтобы выделить диапазон кода и добавить комментарий</li></ol><p><strong>Действия</strong>:</p><ol><li>Просмотрите изменения кода в diff viewer</li><li>Нажмите на номер строки, чтобы выбрать код для рецензирования</li><li>Добавьте комментарий в правой панели (comment/suggestion/concern)</li><li>Нажмите <strong>Send Feedback</strong>, чтобы отправить агенту, или <strong>LGTM</strong> для одобрения</li></ol><p><strong>Вы должны увидеть</strong>: После нажатия Send Feedback браузер закроется, в терминале выведется отформатированное содержимое обратной связи, агент автоматически обработает его.</p><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><p>После выполнения вышеуказанных шагов вы должны уметь:</p><ul><li>[ ] Скрипт установки отображает &quot;plannotator vX.X.X installed to ...&quot;</li><li>[ ] В Claude Code запускается рецензирование плана, браузер автоматически открывает UI</li><li>[ ] В UI можно выделить текст плана, добавить комментарий</li><li>[ ] Нажатие Approve или Request Changes закрывает браузер</li><li>[ ] Выполнение <code>/plannotator-review</code> открывает интерфейс рецензирования кода</li><li>[ ] В рецензировании кода можно добавить комментарий на уровне строки, нажать Send Feedback</li></ul><p><strong>Если какой-либо шаг не работает</strong>, см.:</p><ul><li><a href="./../installation-claude-code/">Руководство по установке Claude Code</a></li><li><a href="./../installation-opencode/">Руководство по установке OpenCode</a></li><li><a href="./../../faq/common-problems/">Часто задаваемые вопросы</a></li></ul><h2 id="предупреждения-о-подводных-камнях" tabindex="-1">Предупреждения о подводных камнях <a class="header-anchor" href="#предупреждения-о-подводных-камнях" aria-label="Permalink to &quot;Предупреждения о подводных камнях&quot;">​</a></h2><p><strong>Ошибка 1</strong>: После установки запуск <code>plannotator</code> выдаёт &quot;command not found&quot;</p><p><strong>Причина</strong>: Переменная окружения PATH не обновлена или требуется перезапуск терминала.</p><p><strong>Решение</strong>:</p><ul><li>macOS/Linux: выполните <code>source ~/.zshrc</code> или <code>source ~/.bashrc</code>, или перезапустите терминал</li><li>Windows: перезапустите PowerShell или CMD</li></ul><p><strong>Ошибка 2</strong>: После установки плагина в Claude Code рецензирование плана не запускается</p><p><strong>Причина</strong>: Claude Code не перезапущен, hook не активирован.</p><p><strong>Решение</strong>: Полностью выйдите из Claude Code (не просто закройте окно), затем откройте заново.</p><p><strong>Ошибка 3</strong>: Браузер не открывается автоматически</p><p><strong>Причина</strong>: Возможно, удалённый режим (например, devcontainer, SSH) или порт занят.</p><p><strong>Решение</strong>:</p><ul><li>Проверьте, установлена ли переменная окружения <code>PLANNOTATOR_REMOTE=1</code></li><li>Посмотрите URL, выведенный в терминале, откройте вручную в браузере</li><li>Подробности см. в разделе <a href="./../../advanced/remote-mode/">Режим удалённого доступа/Devcontainer</a></li></ul><p><strong>Ошибка 4</strong>: В рецензировании кода отображается &quot;No changes&quot;</p><p><strong>Причина</strong>: В данный момент нет незафиксированных изменений git.</p><p><strong>Решение</strong>:</p><ul><li>Сначала выполните <code>git status</code>, чтобы подтвердить наличие изменений</li><li>Или выполните <code>git add</code>, чтобы добавить некоторые файлы в индекс</li><li>Или переключитесь на другой тип diff (например, last commit)</li></ul><h2 id="резюме-урока" tabindex="-1">Резюме урока <a class="header-anchor" href="#резюме-урока" aria-label="Permalink to &quot;Резюме урока&quot;">​</a></h2><p>Plannotator — это локальный инструмент рецензирования, который повышает эффективность рецензирования планов и кода через визуальный UI:</p><p><strong>Основные функции</strong>:</p><ul><li><strong>Рецензирование планов</strong>: Визуальное рецензирование планов, сгенерированных ИИ, с поддержкой точных комментариев</li><li><strong>Рецензирование кода</strong>: Визуальное рецензирование Git diff с поддержкой комментариев на уровне строк</li><li><strong>Обмен URL</strong>: Возможность делиться содержимым рецензирования без бэкенда</li><li><strong>Интеграция с третьими сторонами</strong>: Автоматическое сохранение одобренных планов в Obsidian/Bear</li></ul><p><strong>Ключевые преимущества</strong>:</p><ul><li>Локальное выполнение, безопасность данных</li><li>Визуальный UI, повышение эффективности</li><li>Точная обратная связь, снижение затрат на коммуникацию</li><li>Командная работа без системы учётных записей</li></ul><h2 id="анонс-следующего-урока" tabindex="-1">Анонс следующего урока <a class="header-anchor" href="#анонс-следующего-урока" aria-label="Permalink to &quot;Анонс следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../installation-claude-code/">Установку плагина Claude Code</a></strong>.</p><p>Вы узнаете:</p><ul><li>Подробные шаги установки плагина Claude Code</li><li>Способ ручной настройки hook</li><li>Как проверить успешность установки</li><li>Решения распространённых проблем установки</li></ul></blockquote><hr><h2 id="приложение-справка-по-исходному-коду" tabindex="-1">Приложение: Справка по исходному коду <a class="header-anchor" href="#приложение-справка-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справка по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть и посмотреть расположение исходного кода</strong></summary><blockquote><p>Обновлено: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Номера строк</th></tr></thead><tbody><tr><td>Вход CLI (рецензирование планов)</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L1-L50" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>1-50</td></tr><tr><td>Вход CLI (рецензирование кода)</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L46-L84" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>46-84</td></tr><tr><td>Сервер рецензирования планов</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L1-L200" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>1-200</td></tr><tr><td>Сервер рецензирования кода</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/review.ts#L1-L150" target="_blank" rel="noreferrer"><code>packages/server/review.ts</code></a></td><td>1-150</td></tr><tr><td>Инструменты Git</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L1-L100" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>1-100</td></tr><tr><td>UI рецензирования планов</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>UI рецензирования кода</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>1-200</td></tr></tbody></table><p><strong>Ключевые константы</strong>:</p><ul><li><code>MAX_RETRIES = 5</code>: Количество повторных попыток порта (<code>packages/server/index.ts:80</code>)</li><li><code>RETRY_DELAY_MS = 500</code>: Задержка повторной попытки порта (<code>packages/server/index.ts:80</code>)</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>startPlannotatorServer()</code>: Запуск сервера рецензирования планов (<code>packages/server/index.ts</code>)</li><li><code>startReviewServer()</code>: Запуск сервера рецензирования кода (<code>packages/server/review.ts</code>)</li><li><code>runGitDiff()</code>: Выполнение команды git diff (<code>packages/server/git.ts</code>)</li></ul><p><strong>Переменные окружения</strong>:</p><ul><li><code>PLANNOTATOR_REMOTE</code>: Флаг удалённого режима (<code>apps/hook/server/index.ts:17</code>)</li><li><code>PLANNOTATOR_PORT</code>: Фиксированный порт (<code>apps/hook/server/index.ts:18</code>)</li><li><code>PLANNOTATOR_BROWSER</code>: Пользовательский браузер (<code>apps/hook/README.md:79</code>)</li><li><code>PLANNOTATOR_SHARE</code>: Переключатель обмена URL (<code>apps/hook/server/index.ts:44</code>)</li></ul></details>`,104)])])}const u=s(o,[["render",l]]);export{g as __pageData,u as default};
